resource "aws_cloudwatch_log_group" "checkout_service_logs" {
  name              = "/aws/lambda/checkout-service"
  retention_in_days = 30

  tags = {
    Name          = "checkout-service-logs"
    Environment   = "production"
    FinOpsAction  = "SET_RETENTION"
    FinOpsReviewed = "true"
  }
}

nat-0c1d2e3f4a5b6c701.terraform_block:
resource "aws_eip" "nat_gw_legacy_eip" {
  domain = "vpc"

  tags = {
    Name          = "nat-gw-legacy-eip"
    FinOpsAction  = "DESTROY"
    FinOpsReviewed = "true"
  }

  lifecycle {
    prevent_destroy = false
  }
}

resource "aws_nat_gateway" "nat_gw_legacy_batch" {
  allocation_id = aws_eip.nat_gw_legacy_eip.id
  subnet_id     = "subnet-0b2c3d4e"

  tags = {
    Name          = "nat-gw-legacy-batch"
    Environment   = "production"
    FinOpsAction  = "DESTROY"
    FinOpsReviewed = "true"
  }

  lifecycle {
    prevent_destroy = false
  }
}

